/* Convert physical properties to logical equivalents:
   margin-left -> margin-inline-start
   padding-top/bottom -> padding-block
   border-right -> border-inline-end
   width -> inline-size
   height -> block-size */
.lp-article {
  max-width: 600px;
  padding: 24px;
}
.lp-title {
  margin-bottom: 12px;
  padding-bottom: 12px;
  border-bottom: 2px solid #007bff;
}
.lp-body {
  margin-bottom: 16px;
  line-height: 1.6;
}
.lp-sidebar {
  margin-left: 24px;
  padding: 16px;
  border-left: 4px solid #e0e0e0;
  background-color: #f8f9fa;
}

